transform:
@{
    var emp = EpicData.FirstOrDefault(b => b.TableName == "EMP");
    if (emp != null) emp.Values["STATUS"] = "I";
    modelJson["data"] = JArray.FromObject(EpicData.Select(b => new { name = b.TableName, values = b.Values }));
}
@Raw(modelJson.ToString())

@{
    var addr = EpicData.FirstOrDefault(b => b.TableName == "ADDRESS");
    var line2 = addr?.Values.ContainsKey("LINE2") == true ? addr.Values["LINE2"]?.ToString() : null;
}
{
  "line1": @Value("ADDRESS", "LINE1"),
@if (!string.IsNullOrEmpty(line2)) {
  "line2": "@line2",
}
  "city": @Value("ADDRESS", "CITY"),
  "state": @Value("ADDRESS", "STATE"),
  "zip": @Value("ADDRESS", "ZIP")
}
